res[\"file_created\"] = 0.0\n72\t        scores[\"valid_compression_days\"] = 0.0\n73\t        scores[\"valid_explosion_amplitude\"] = 0.0\n74\t        scores[\"hv_computed\"] = 0.0\n75\t        scores[\"percentile_used\"] = 0.0\n76\t        return scores\n77\t\n78\t    scores[\"file_created\"] = 1.0\n79\t    content = result_file.read_text().strip()\n80\t\n81\t    no_result_phrases = [\"无符合\", \"没有\", \"none\"]\n82\t    if any(p in content.lower() for p in no_result_phrases):\n83\t        scores[\"valid_compression_days\"] = 1.0\n84\t        scores[\"valid_explosion_amplitude\"] = 1.0\n85\t    else:\n86\t        lines = [l.strip() for l in content.splitlines()\n87\t                 if l.strip() and not l.startswith(\"#\") and \"代码\" not in l]\n88\t\n89\t        records = []\n90\t        for line in lines:\n91\t            parts = re.split(r'[,\\s\\t]+', line)\n92\t            if len(parts) >= 5:\n93\t                try:\n94\t                    compression = int(parts[1])\n95\t                    amplitude = float(parts[3].replace('%', ''))\n96\t                    records.append((compression, amplitude))\n97\t                except:\n98\t                    pass\n99\t\n100\t        valid_days = [r for r in records if r[0] >= 10]\n101\t        scores[\"valid_compression_days\"] = 1.0 if len(valid_days) == len(records) and len(records) > 0 else (0.5 if len(valid_days) > 0 else 0.0)\n102\t\n103\t        valid_amp = [r for r in records if r[1] > 7.0]\n104\t        scores[\"valid_explosion_amplitude\"] = 1.0 if len(valid_amp) == len(records) and len(records) > 0 else (0.5 if len(valid_amp) > 0 else 0.0)\n105\t\n106\t    transcript_str = str(transcript).lower()\n107\t    scores[\"hv_computed\"] = 1.0 if any(kw in transcript_str for kw in\n108\t        [\"historical.*vol\", \"hv10\", \"历史波动率\", \"log.*return.*std\", \"realized.*vol\"]) else 0.0\n109\t    scores[\"percentile_used\"] = 1.0 if any(kw in transcript_str for kw in\n110\t        [\"percentile\", \"分位数\", \"qua